// Build HTML notification for order submission results
const input = $('Sub-Workflow Input').first().json;
const lines = input.validatedLines || [];
const invalidLines = input.invalidLines || [];
const summary = input.summary || { valid: 0, invalid: 0, warnings: 0 };
const senderEmail = input.senderEmail || 'unknown';
const emailSubject = input.emailSubject || 'N/A';
const submissionResult = input.submissionResult || {};

// Submission results banner
const success = submissionResult.submitted || false;
const bannerColor = success ? '#d4edda' : '#f8d7da';
const bannerTextColor = success ? '#155724' : '#721c24';
const statusText = success ? 'NARUDŽBA USPJEŠNO POSLANA' : 'SLANJE NARUDŽBE NEUSPJELO';

let html = `<div style="padding:12px 16px;background:${bannerColor};color:${bannerTextColor};border-radius:6px;margin-bottom:16px;font-weight:bold;">`;
html += statusText;
if (submissionResult.orders && submissionResult.orders.length > 0) {
  html += `<br>ID narudžbi: ${submissionResult.orders.map(o => o.orderId).join(', ')}`;
}
if (submissionResult.errors && submissionResult.errors.length > 0) {
  html += `<br>Greške: ${submissionResult.errors.map(e => typeof e.error === 'string' ? e.error : (e.error && e.error.message) || JSON.stringify(e.error)).join('; ')}`;
}
const missingDpIds = [...new Set(invalidLines.filter(l => !l.customer).map(l => l.pharmacyId).filter(Boolean))];
if (missingDpIds.length > 0) {
  html += `<br>NEDOSTAJU KUPCI ZA MJESTA ISPORUKE: ${missingDpIds.join(', ')}`;
}
html += `</div>`;

html += `<h2>Obavijest o prednarudžbi</h2>`;
html += `<p><strong>Od:</strong> ${senderEmail}<br>`;
html += `<strong>Predmet:</strong> ${emailSubject}<br>`;
html += `<strong>Redaka:</strong> ${lines.length} | `;
html += `<strong>Ispravnih:</strong> ${summary.valid} | `;
html += `<strong>Neispravnih:</strong> ${summary.invalid} | `;
html += `<strong>S upozorenjima:</strong> ${summary.warnings}</p>`;

html += `<table border="1" cellpadding="5" cellspacing="0" style="border-collapse:collapse;font-size:13px;">`;
html += `<tr style="background:#f0f0f0;"><th>#</th><th>Šifra ljekarne</th><th>Ljekarna</th><th>Šifra kupca</th><th>Šifra artikla</th><th>Naziv artikla</th><th>Kol.</th><th>Rabat</th><th>JM</th></tr>`;

const allLines = lines;
for (let i = 0; i < allLines.length; i++) {
  const line = allLines[i];
  const bgColor = !line.valid ? '#ffe0e0' :
                  line.warnings && line.warnings.length > 0 ? '#fff3cd' :
                  (line.parseMethod === 'AI_EXTRACTED' || line.parseMethod === 'AI_VERIFIED' || line.parseMethod === 'EMAIL_BODY_AI' || line.parseMethod === 'EMAIL_BODY_AI_VERIFIED') ? '#e0e7ff' : '#e0ffe0';

  html += `<tr style="background:${bgColor};">`;
  html += `<td>${i + 1}</td>`;
  html += `<td>${line.pharmacyId || line.deliveryPlace || '-'}</td>`;
  html += `<td>${line.pharmacyName || line.deliveryPlaceName || '-'}</td>`;
  html += `<td>${line.customer || '-'}</td>`;
  html += `<td>${line.articleId || line.drugCode || '-'}</td>`;
  html += `<td>${line.articleName || '-'}</td>`;
  html += `<td>${line.quantity}</td>`;
  html += `<td>${line.discount ? line.discount + '%' : '-'}</td>`;
  html += `<td>${line.unit || 'kom'}</td>`;
  html += `</tr>`;
}
html += `</table>`;

if (summary.invalid > 0) {
  html += `<p style="color:red;"><strong>Upozorenje:</strong> ${summary.invalid} redak(a) ima greške validacije i preskočen(o) je.</p>`;
}

const parseMethod = input.parseMethod || '';
const parseConfidence = input.parseConfidence || null;
if (parseMethod === 'AI_EXTRACTED' || parseMethod === 'AI_VERIFIED' || parseMethod === 'EMAIL_BODY_AI' || parseMethod === 'EMAIL_BODY_AI_VERIFIED') {
  const methodLabel = (parseMethod === 'AI_VERIFIED' || parseMethod === 'EMAIL_BODY_AI_VERIFIED') ? 'AI verificirano' : 'AI ekstrakcija (neprovjereno)';
  const confText = parseConfidence ? ` — pouzdanost: ${parseConfidence}%` : '';
  html += `<p style="color:#3b5998;"><strong>Napomena:</strong> ${methodLabel}${confText} (AI redci označeni plavom).</p>`;
}

// Verification issues from AI
const verificationIssues = input.verificationIssues || [];
if (verificationIssues.length > 0) {
  html += `<div style="padding:8px 12px;background:#fff3cd;color:#856404;border-radius:4px;margin-top:12px;">`;
  html += `<strong>AI verifikacija pronašla ${verificationIssues.length} problem(a):</strong><ul style="margin:4px 0;">`;
  for (const issue of verificationIssues) {
    html += `<li>${issue}</li>`;
  }
  html += `</ul></div>`;
}

// Original email body
const emailBodyHtml = input.emailBodyHtml || '';
if (emailBodyHtml) {
  html += `<hr style="margin:20px 0;">`;
  html += `<h3>Originalni email</h3>`;
  html += `<blockquote style="border-left:3px solid #ccc;padding:8px 16px;margin:8px 0;color:#555;">${emailBodyHtml}</blockquote>`;
}

const binary = $('Sub-Workflow Input').first().binary || {};

return [{
  json: {
    ...input,
    notificationHtml: html
  },
  binary: binary
}];

// Build Graph API sendMail payload with all attachments
const item = $input.first();
const json = item.json;
const binary = item.binary || {};
const binaryKeys = Object.keys(binary);

const xlsxSuffix = json.xlsxFileName ? ` [${json.xlsxFileName}]` : '';
const subject = `Obavijest o prednarudžbi: ${json.senderEmail} (${json.lineCount} redaka)${xlsxSuffix} — ${json.receivedAt ? new Date(json.receivedAt).toLocaleDateString('hr-HR') : ''}`;

const message = {
  subject,
  body: { contentType: 'HTML', content: json.notificationHtml },
  toRecipients: json.config.notifyEmail.split(',').map(e => ({ emailAddress: { address: e.trim() } }))
};

if (binaryKeys.length > 0) {
  message.attachments = binaryKeys.map(key => {
    const att = binary[key];
    return {
      '@odata.type': '#microsoft.graph.fileAttachment',
      name: att.fileName || 'attachment',
      contentType: att.mimeType || 'application/octet-stream',
      contentBytes: att.data
    };
  });
}

return [{ json: { sendMailPayload: { message } } }];
